Method.Source:
public static void main(Args args)
{
    if(ETG_Parameters::find().ETGIsDimensionValidationRequired == NoYes::Yes)
    {
        DefaultDimensionView            defaultDimView;
        DimensionAttributeSetItem       dimAttrSetItem;
        DimensionAttribute              dimAttribute;
        CustInvoiceTable                custInvoiceTable;
        DimensionEnumeration            dimensionSetId = DimensionCache::getDimensionAttributeSetForLedger();

        select firstonly DefaultDimension from custInvoiceTable
        where custInvoiceTable.RecId == args.record().RecId;

        select firstonly RecId from dimAttrSetItem
            where  dimAttrSetItem.DimensionAttributeSet == dimensionSetId
        join Name from dimAttribute
            where dimAttribute.RecId == dimAttrSetItem.DimensionAttribute
                && dimAttribute.Type != DimensionAttributeType::MainAccount
        notexists join defaultDimView
            where defaultDimView.Name ==  dimAttribute.Name
                && defaultDimView.DefaultDimension == custInvoiceTable.DefaultDimension;

        if(dimAttrSetItem)
        {
            if(Box::yesNoAxaptaForm(strFmt('Few financial dimensions are not filled in. Do you want to update? '), DialogButton::Yes) == DialogButton::Yes)
            {
                throw warning('Update has been canceled');
            }
        }
    }

    next main(args);
}
